export type IconName = keyof typeof iconComponents;

interface IconPropsWithName extends React.HTMLAttributes<HTMLDivElement> {
    name: IconName;
    nameOverride?: string;
    customIcon?: React.ReactNode;
}

export const Icon = ({ name, nameOverride, customIcon, className, ...props }: IconPropsWithName) => {
    const IconComponent = iconComponents[name];

    if (!IconComponent) {
        return null;
    }

    return (
        <div className={cn('tech-icon', className)} {...props}>
            {customIcon || <IconComponent />}
            {nameOverride || name}
        </div>
    );
};
